#!/usr/bin/env python3
"""gen-synth-knot.py — emit a MINIMAL, loadable dense KNOT (magic b"KNOT")
for fat-station smoke / boot verification. NO numpy required.

This replicates the dense KNOT byte layout written by KnotWriter in
encode-knot.py (and consumed by KnotWeights::load_mmap in
distributed-inference/src/loader.rs:1051-1107):

    b"KNOT" + u16 version(=1) + u32 meta_len + meta_json
    + pad to 4 + 1 codec marker byte (0x20)  +  payload

The loader does NOT gate the KNOT version field (only GKQ2 gates on
header_version 2/3). resolve_all() in model.rs:584 needs, per the config's
num_layers, these underscore-keyed tensors (the writer appends ".bin";
parse_tensors strips it -> metadata key has no ".bin"):

    token_embd.weight, output_norm.weight  (output.weight optional -> tied)
    blk.{i}.attn_norm/attn_q/attn_k/attn_v/attn_output.weight
    blk.{i}.ffn_norm/ffn_gate/ffn_up/ffn_down.weight

All tensors are F32 (avoids the Q8_0 dequant path). They are ZEROED — the
forward pass is never exercised by /health, which only needs a successful
load + resolve_all + config-driven buffer allocation. Dims come solely from
the `config` block (loader.rs:158 KnotConfig).

Usage:  python gen-synth-knot.py C:\\Temp\\synth.knot
"""
import json, struct, sys
from pathlib import Path

# Tiny llama-shaped config. All 7 required usize fields present (KnotConfig).
HIDDEN  = 64
LAYERS  = 2
HEADS   = 4
KV_H    = 4
HEAD_D  = 16          # HEADS * HEAD_D == HIDDEN
FFN     = 128
VOCAB   = 256

CONFIG = {
    "hidden_dim": HIDDEN, "num_layers": LAYERS,
    "num_heads": HEADS, "num_kv_heads": KV_H,
    "head_dim": HEAD_D, "intermediate_size": FFN,
    "vocab_size": VOCAB, "rms_norm_eps": 1e-5,
    "rope_theta": 10000.0, "arch": "llama",
}

def f32_zeros(n: int) -> bytes:
    return b"\x00\x00\x00\x00" * n   # n little-endian f32 zeros

def main() -> None:
    out = Path(sys.argv[1] if len(sys.argv) > 1 else r"C:\Temp\synth.knot")

    # (canonical_dotted_name, element_count)
    tensors: list[tuple[str, int]] = [
        ("token_embd.weight", VOCAB * HIDDEN),
        ("output_norm.weight", HIDDEN),
        ("output.weight", VOCAB * HIDDEN),      # explicit lm_head (untied)
    ]
    for i in range(LAYERS):
        tensors += [
            (f"blk.{i}.attn_norm.weight",   HIDDEN),
            (f"blk.{i}.attn_q.weight",      (HEADS * HEAD_D) * HIDDEN),
            (f"blk.{i}.attn_k.weight",      (KV_H  * HEAD_D) * HIDDEN),
            (f"blk.{i}.attn_v.weight",      (KV_H  * HEAD_D) * HIDDEN),
            (f"blk.{i}.attn_output.weight", HIDDEN * (HEADS * HEAD_D)),
            (f"blk.{i}.ffn_norm.weight",    HIDDEN),
            (f"blk.{i}.ffn_gate.weight",    FFN * HIDDEN),
            (f"blk.{i}.ffn_up.weight",      FFN * HIDDEN),
            (f"blk.{i}.ffn_down.weight",    HIDDEN * FFN),
        ]

    tensor_meta: dict = {}
    payload = bytearray()
    for canon, n in tensors:
        raw = f32_zeros(n)
        key = canon.replace(".", "_") + ".bin"   # -> blk_0_attn_q_weight.bin
        tensor_meta[key] = {"offset": len(payload), "length": len(raw), "type": "F32"}
        payload += raw

    meta = {"name": "synth-mini-llama", "arch": "llama",
            "config": CONFIG, "tensors": tensor_meta}
    meta_bytes = json.dumps(meta).encode()

    header = b"KNOT" + struct.pack("<H", 1) + struct.pack("<I", len(meta_bytes)) + meta_bytes
    header += b"\x00" * ((-len(header)) % 4)   # pad to 4
    header += b"\x20"                            # codec marker (fp32 default)

    out.parent.mkdir(parents=True, exist_ok=True)
    with open(out, "wb") as f:
        f.write(header)
        f.write(payload)
    print(f"[gen-synth-knot] wrote {out} ({out.stat().st_size} bytes, "
          f"{len(tensors)} tensors, layers={LAYERS} hidden={HIDDEN} vocab={VOCAB})")

if __name__ == "__main__":
    main()
